CREATE TABLE IF NOT EXISTS equipment (
    EQUIP_ID INTEGER PRIMARY KEY,
    EQUIP_CODE VARCHAR(50),
    EQUIP_NAME VARCHAR(200),
    EQUIP_TYPE VARCHAR(50),
    PARENT_EQUIP_ID INTEGER,
    MAKER VARCHAR(100),
    MODEL VARCHAR(100),
    SERIAL_NO VARCHAR(100),
    LOCATION VARCHAR(200),
    CRITICALITY VARCHAR(20),
    STATUS VARCHAR(20)
);

